export const BOOK_THEMES = {
  personal: {
    key: 'personal',
    name: '个人账本',
    primary: '#F5A623',
    primaryLight: '#F7B84D',
    primaryDark: '#E8940C',
    cardBg: '#FFFBF5',
    navBar: '#F5A623',
    gradient: 'linear-gradient(135deg, #F5A623 0%, #F7B84D 100%)'
  },
  shared: {
    key: 'shared',
    name: '集体账本',
    primary: '#6A5ACD',
    primaryLight: '#8B7DD8',
    primaryDark: '#5A4AB8',
    cardBg: '#F8F4FF',
    navBar: '#6A5ACD',
    gradient: 'linear-gradient(135deg, #6A5ACD 0%, #8B7DD8 100%)'
  }
};

export function getBookThemeKey(typeOrTab) {
  if (typeOrTab === 1 || typeOrTab === 'shared') {
    return 'shared';
  }
  return 'personal';
}

export function getBookTheme(typeOrTab) {
  return BOOK_THEMES[getBookThemeKey(typeOrTab)];
}

export function applyNavBarTheme(typeOrTab) {
  const theme = getBookTheme(typeOrTab);
  uni.setNavigationBarColor({
    frontColor: '#ffffff',
    backgroundColor: theme.navBar,
    animation: {
      duration: 200,
      timingFunc: 'easeIn'
    }
  });
}
